import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import "./LoginPage.css";

const LoginPage: React.FC = () => {
    const [email, setEmail] = useState("");
    const [password, setPassword] = useState("");
    const [rememberMe, setRememberMe] = useState(false);
    const navigate = useNavigate();

    const handleLogin = () => {
        console.log("Giriş yapılıyor:", { email, password, rememberMe });
        navigate("/dashboard"); // Başarıyla giriş yaptıysa yönlendir
    };

    return (
        <div className="flex items-center justify-center min-h-screen bg-gray-100">
            <div className="bg-white p-8 rounded-lg shadow-lg w-96">
                <h2 className="text-2xl font-bold text-center mb-6">Giriş Yap</h2>

                {/* Email Girişi */}
                <div className="mb-4">
                    <label className="block text-sm font-medium text-gray-700">E-Posta veya Kullanıcı Adı</label>
                    <input
                        type="text"
                        className="mt-1 p-2 w-full border rounded-lg"
                        placeholder="example@email.com"
                        value={email}
                        onChange={(e) => setEmail(e.target.value)}
                    />
                </div>

                {/* Şifre Girişi */}
                <div className="mb-4">
                    <label className="block text-sm font-medium text-gray-700">Şifre</label>
                    <input
                        type="password"
                        className="mt-1 p-2 w-full border rounded-lg"
                        placeholder="••••••••"
                        value={password}
                        onChange={(e) => setPassword(e.target.value)}
                    />
                </div>

                {/* Beni Hatırla & Şifremi Unuttum */}
                <div className="flex justify-between items-center mb-4">
                    <label className="flex items-center text-sm">
                        <input
                            type="checkbox"
                            className="mr-2"
                            checked={rememberMe}
                            onChange={(e) => setRememberMe(e.target.checked)}
                        />
                        Beni hatırla
                    </label>
                    <a href="#" className="text-blue-500 text-sm">Şifremi Unuttum?</a>
                </div>

                {/* Giriş Butonu */}
                <button
                    className="w-full bg-blue-600 text-white p-2 rounded-lg hover:bg-blue-700 transition"
                    onClick={handleLogin}
                >
                    Giriş Yap
                </button>

                {/* Footer - Dil Seçici */}
                <div className="text-center mt-4 text-sm text-gray-600">
                    <select className="p-2 border rounded-lg">
                        <option value="tr">Türkçe</option>
                        <option value="en">English</option>
                    </select>
                </div>
            </div>
        </div>
    );
};

export default LoginPage;
